import React from 'react';
import { useFormik } from 'formik';

const SignupForm = () => {
  const formik = useFormik({
    initialValues: {
      Name: '',
      address: '',
      mobile: '',
      city: '',
      district: '',
      census: '',
      feeder:  '',
    },
    onSubmit: (values) => {
      alert(JSON.stringify(values, null, 2));
    },
  });

  return (
    <form onSubmit={formik.handleSubmit}>
      <label htmlFor="Name">Name :</label>
      <input  id="Name" name="Name" type="text" onChange={formik.handleChange} value={formik.values.Name} /><br /><br />

      <label htmlFor="address">Address :</label>
      <input id="Address" name="Address" type="text" onChange={formik.handleChange} value={formik.values.Address} /><br /><br />

      <label htmlFor="Mobile">Mobile Number :</label>
      <input id="mobile" name="mobile" type="text" onChange={formik.handleChange} value={formik.values.mobile} /><br /><br />

      <label htmlFor="city">City :</label>
      <input id="city" name="city" type="text" onChange={formik.handleChange} value={formik.values.city} /><br /><br />

      <label htmlFor="district">District :</label>
      <input id="district" name="district" type="text" onChange={formik.handleChange} value={formik.values.district} /><br /><br />

      <label htmlFor="census">Census Code :</label>
      <input id="census" name="census" type="text" onChange={formik.handleChange} value={formik.values.census} /><br /><br />

      <label htmlFor="feeder">Feeder Code :</label>
      <input id="feeder" name="feeder" type="text" onChange={formik.handleChange} value={formik.values.feeder} /><br /><br />

      <button type="submit">Submit</button>
    </form>
  );
};

export default SignupForm;
